4	describe("Pixel Art Scaler", () => {
5	  it("should return an empty image for an empty input image", () => {
6	    expect(scalePixelArt([], 2)).toEqual([]);
7	  });
8	  it("should return an unchanged copy of the input when scale factor is 1", () => {
9	    expect(scalePixelArt(["AB", "CD"], 1)).toEqual(["AB", "CD"]);
10	  });
11	  it("should replicate a single pixel horizontally and vertically by the scale factor", () => {
12	    expect(scalePixelArt(["A"], 3)).toEqual(["AAA", "AAA", "AAA"]);
13	  });
14	  it("should scale a single-row image by replicating each pixel horizontally and the row vertically", () => {
15	    expect(scalePixelArt(["AB"], 2)).toEqual(["AABB", "AABB"]);
16	  });
17	  it.todo("should scale a single-column image by replicating each row vertically");
18	  it.todo("should scale a multi-row, multi-column image by replicating pixels horizontally and rows vertically");
19	  it.todo("should preserve exact character values without smoothing or blending");
20	});
