1	export function scalePixelArt(image: string[], scale: number): string[] {
2	  const scaledRow = (row: string) => [...row].map((ch) => ch.repeat(scale)).join("");
3	  return image.flatMap((row) => Array(scale).fill(scaledRow(row)));
4	}
